import React from 'react';
import { Link } from 'react-router-dom';
import { FaUser, FaComment, FaThumbsUp, FaCalendarAlt } from 'react-icons/fa';
import formatDate from '../utils/formatDate';

const ForumPostCard = ({ post }) => {
  const { 
    _id, 
    title, 
    description, 
    author, 
    createdAt, 
    comments = [], 
    likes = [] 
  } = post;

  // Truncate description if it's too long
  const truncateText = (text, maxLength = 150) => {
    if (!text) return '';
    if (text.length <= maxLength) return text;
    return text.substr(0, maxLength) + '...';
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-4 mb-4 hover:shadow-lg transition duration-300">
      <Link to={`/forum/post/${_id}`} className="hover:no-underline">
        <h3 className="text-xl font-semibold text-blue-800 mb-2 hover:text-blue-600">
          {title}
        </h3>
      </Link>
      
      <p className="text-gray-700 mb-3">{truncateText(description)}</p>
      
      <div className="flex items-center text-gray-500 mb-3">
        <FaUser className="mr-1" />
        <span className="mr-4">{author?.name || 'Anonymous'}</span>
        
        <FaCalendarAlt className="mr-1" />
        <span>{formatDate(createdAt)}</span>
      </div>
      
      <div className="flex items-center justify-between border-t pt-3">
        <div className="flex space-x-4">
          <div className="flex items-center text-blue-600">
            <FaThumbsUp className="mr-1" />
            <span>{likes.length}</span>
          </div>
          <div className="flex items-center text-green-600">
            <FaComment className="mr-1" />
            <span>{comments.length}</span>
          </div>
        </div>
        
        <Link 
          to={`/forum/post/${_id}`} 
          className="text-blue-600 hover:text-blue-800 font-medium"
        >
          Read more
        </Link>
      </div>
    </div>
  );
};

export default ForumPostCard;
